// layered products and a running mean
let a = (3 + 4) * (5 - 2);
let b = a * a - 7;
let c = b % 100;
print a;
print b;
print c;
print (a + b + c) / 3;

// division, remainder reconstruction, nested squares
let x = 100;
let y = x / 7;
let z = x - y * 7;
print y;
print z;
print y * y + z * z;
print (x + y) / (z + 1);

// negative dividend: truncation toward zero and sign of remainder
let n = 0 - 47;
let d = 5;
let q = n / d;
let r = n % d;
print q;
print r;
print q * d + r;
print (n * n) % 1000;

// repeat accumulator: sum of squares, then fold it two ways
let sum = 0;
let i = 0;
repeat 10 {
  i = i + 1;
  sum = sum + i * i;
}
print i;
print sum;
print sum / i;
print sum % i;

// nested repeat: a multiplication-table total
let total = 0;
let a = 0;
repeat 5 {
  a = a + 1;
  let b = 0;
  repeat 4 {
    b = b + 1;
    total = total + a * b;
  }
}
print a;
print total;
print total / 10;
print total * 2 - 1;

// branch-selected arithmetic over a loop
let acc = 0;
let k = 0;
repeat 12 {
  k = k + 1;
  if k % 3 == 0 && k % 2 == 0 {
    acc = acc + k * 10;
  } else if k % 3 == 0 {
    acc = acc + k;
  } else if k % 2 == 0 {
    acc = acc - 1;
  } else {
    acc = acc + 2;
  }
}
print k;
print acc;
print acc % 7;
print (acc + k) * 2;

// nested-parentheses stress and a triangular fold
let p = ((2 + 3) * (4 + 1)) - ((6 - 2) * (1 + 1));
let s = (p * (p - 1)) / 2;
print p;
print s;
print s % p;
print (s + p) / (p - 8);

// Horner-style polynomial evaluation inside a loop
let coeffs_hi = 3;
let x = 2;
let val = coeffs_hi;
let step = 0;
repeat 4 {
  step = step + 1;
  val = val * x + step;
}
print x;
print step;
print val;
print val % 100;

// gcd-flavoured remainder chain (bounded, no while)
let a = 84;
let b = 30;
let r0 = a % b;
let r1 = b % r0;
let r2 = r0 % r1;
print r0;
print r1;
print r2;
print (a / b) + (b / r0) + (r0 / r1);

// alternating-sign accumulation of squares
let total = 0;
let i = 0;
let sign = 1;
repeat 9 {
  i = i + 1;
  total = total + sign * i * i;
  sign = 0 - sign;
}
print i;
print total;
print total * total;
print (total * total) % 97;

// bounded product (factorial) with modular reductions
let prod = 1;
let m = 0;
repeat 6 {
  m = m + 1;
  prod = prod * m;
}
print m;
print prod;
print prod / 8;
print prod % 1000;

// layered mixed operators exercising precedence
let a = 9;
let b = 4;
let c = 2;
print a * b - c * c;
print (a - b) * (a + b);
print a * a % (b * c);
print (a * b + c) / (b - c);

// triangular numbers and their successive differences
let t = 0;
let n = 0;
let last = 0;
repeat 8 {
  n = n + 1;
  last = t;
  t = t + n;
}
print n;
print t;
print t - last;
print t * (t + 1) / 2;

// digit-sum of a number via repeated div/mod
let num = 987654;
let digits = 0;
let count = 0;
let cur = num;
repeat 6 {
  digits = digits + cur % 10;
  cur = cur / 10;
  count = count + 1;
}
print count;
print digits;
print cur;
print digits * digits - num % 100;

// power of two by doubling, then recombine
let p = 1;
let e = 0;
repeat 10 {
  p = p * 2;
  e = e + 1;
}
print e;
print p;
print p - 1;
print p / 4 + p % 3;

// clamp two values with if/else-if, then combine
let x = 37;
let y = 58;
let lo = 20;
let hi = 50;
let cx = 0;
if x < lo { cx = lo; } else if x > hi { cx = hi; } else { cx = x; }
let cy = 0;
if y < lo { cy = lo; } else if y > hi { cy = hi; } else { cy = y; }
print cx;
print cy;
print cx + cy;
print (cx * cy) % 101;

// nested repeat building a checkerboard parity sum
let s = 0;
let row = 0;
repeat 4 {
  row = row + 1;
  let col = 0;
  repeat 4 {
    col = col + 1;
    if (row + col) % 2 == 0 {
      s = s + row * col;
    } else {
      s = s - 1;
    }
  }
}
print row;
print s;
print s % 5;
print (s + 100) / 3;

// continued-fraction-style nested division of 355/113
let a = 355;
let b = 113;
let w0 = a / b;
let f0 = a % b;
let w1 = b / f0;
let f1 = b % f0;
print w0;
print f0;
print w1;
print w0 * 100 + w1 * f1;

// running min and max over a generated sequence
let seed = 7;
let cur = seed;
let mx = seed;
let mn = seed;
let step = 0;
repeat 8 {
  step = step + 1;
  cur = (cur * 5 + 3) % 97;
  if cur > mx { mx = cur; }
  if cur < mn { mn = cur; }
}
print step;
print mx;
print mn;
print mx - mn;

// weighted dot-product accumulation with block-local terms
let dot = 0;
let i = 0;
repeat 6 {
  i = i + 1;
  let w = i * 2 - 1;
  let v = 10 - i;
  dot = dot + w * v;
}
print i;
print dot;
print dot / i;
print dot % i;

// nested arithmetic identity check, verdict via branch
let a = 6;
let b = 5;
let lhs = (a + b) * (a + b);
let rhs = a * a + 2 * a * b + b * b;
let diff = lhs - rhs;
print lhs;
print rhs;
print diff;
if diff == 0 { print (a * b) % 7; } else { print 0 - 1; }

// balanced-ternary-style accumulation of powers of three
let value = 0;
let power = 1;
let j = 0;
repeat 5 {
  j = j + 1;
  value = value + (j % 3 - 1) * power;
  power = power * 3;
}
print j;
print power;
print value;
print (value + power) % 11;

// stacked square and cube layers of a pyramid
let layers = 0;
let squares = 0;
let cubes = 0;
repeat 7 {
  layers = layers + 1;
  squares = squares + layers * layers;
  cubes = cubes + layers * layers * layers;
}
print layers;
print squares;
print cubes;
print cubes - squares * squares % 100;

// classify n by range, print a computed code per bucket
let n = 0;
repeat 12 {
  let out = 0;
  if n < 3 {
    out = n * 10;
  } else if n < 7 {
    out = n * 100;
  } else {
    out = n * 1000;
  }
  print out;
  n = n + 1;
}

// fizzbuzz as computed codes over 1..20
let i = 1;
repeat 20 {
  let code = 0;
  if i % 15 == 0 {
    code = 9999;
  } else if i % 3 == 0 {
    code = i * 3;
  } else if i % 5 == 0 {
    code = i * 5;
  } else {
    code = i;
  }
  print code;
  i = i + 1;
}

// sign classifier over -5..5, computed squares
let n = 0 - 5;
repeat 11 {
  let s = 0;
  if n < 0 {
    s = 0 - (n * n);
  } else if n == 0 {
    s = 100;
  } else {
    s = n * n;
  }
  print s;
  n = n + 1;
}

// grade buckets from a linear score
let base = 40;
let step = 7;
let k = 0;
repeat 9 {
  let score = base + step * k;
  let grade = 0;
  if score >= 90 {
    grade = 4;
  } else if score >= 80 {
    grade = 3;
  } else if score >= 70 {
    grade = 2;
  } else if score >= 60 {
    grade = 1;
  } else {
    grade = 0;
  }
  print score;
  print grade;
  k = k + 1;
}

// leap-year-style divisibility classification
let y = 1996;
repeat 10 {
  let kind = 0;
  if y % 400 == 0 {
    kind = 3;
  } else if y % 100 == 0 {
    kind = 1;
  } else if y % 4 == 0 {
    kind = 2;
  } else {
    kind = 0;
  }
  print y;
  print kind;
  y = y + 1;
}

// temperature bands over a rising scale
let t = 0 - 10;
repeat 8 {
  let band = 0;
  if t <= 0 {
    band = 0 - 1;
  } else if t < 15 {
    band = 1;
  } else if t < 25 {
    band = 2;
  } else {
    band = 3;
  }
  print t;
  print band;
  t = t + 6;
}

// classify by last decimal digit
let n = 100;
repeat 12 {
  let d = n % 10;
  let cls = 0;
  if d == 0 {
    cls = 500;
  } else if d % 2 == 0 {
    cls = n + d;
  } else {
    cls = n - d;
  }
  print cls;
  n = n + 3;
}

// quadrant classification of computed coordinates
let i = 0;
repeat 8 {
  let x = i - 4;
  let y = 3 - i;
  let q = 0;
  if x >= 0 && y >= 0 {
    q = 1;
  } else if x < 0 && y >= 0 {
    q = 2;
  } else if x < 0 && y < 0 {
    q = 3;
  } else {
    q = 4;
  }
  print q;
  print x * 10 + y;
  i = i + 1;
}

// classify a running sum of squares
let sum = 0;
let i = 1;
repeat 10 {
  sum = sum + i * i;
  let tag = 0;
  if sum > 200 {
    tag = 3;
  } else if sum % 2 == 0 {
    tag = 2;
  } else {
    tag = 1;
  }
  print sum;
  print tag;
  i = i + 1;
}

// triangle kind by side lengths
let a = 3;
let b = 4;
let i = 0;
repeat 6 {
  let c = a + i;
  let kind = 0;
  if a == b && b == c {
    kind = 3;
  } else if a == b || b == c || a == c {
    kind = 2;
  } else {
    kind = 1;
  }
  print c;
  print kind;
  i = i + 1;
}

// magnitude bands after computing absolute value
let n = 0 - 40;
repeat 9 {
  let mag = n;
  if mag < 0 {
    mag = 0 - mag;
  }
  let band = 0;
  if mag < 10 {
    band = 0;
  } else if mag < 20 {
    band = 1;
  } else if mag < 30 {
    band = 2;
  } else {
    band = 3;
  }
  print mag;
  print band;
  n = n + 10;
}

// branch picks a nested-repeat computation
let n = 1;
repeat 6 {
  let val = 0;
  if n % 2 == 0 {
    let s = 0;
    repeat n {
      s = s + n;
    }
    val = s;
  } else {
    let p = 1;
    repeat n {
      p = p * 2;
    }
    val = p;
  }
  print val;
  n = n + 1;
}

// classify by remainder mod 4
let i = 0;
repeat 16 {
  let r = i % 4;
  let out = 0;
  if r == 0 {
    out = i;
  } else if r == 1 {
    out = i + 100;
  } else if r == 2 {
    out = i * 2;
  } else {
    out = i - 1;
  }
  print out;
  i = i + 1;
}

// divisibility combos with boolean logic
let n = 1;
repeat 15 {
  let by2 = n % 2 == 0;
  let by3 = n % 3 == 0;
  let tag = 0;
  if by2 && by3 {
    tag = 6;
  } else if by2 || by3 {
    tag = n + 1;
  } else if !by2 && !by3 {
    tag = n * n;
  } else {
    tag = 0;
  }
  print tag;
  n = n + 1;
}

// one collatz step chosen by parity
let n = 7;
repeat 10 {
  let next = 0;
  if n % 2 == 0 {
    next = n / 2;
  } else {
    next = 3 * n + 1;
  }
  print n;
  print next;
  n = next;
}

// classify a parabola value across its sign changes
let x = 0;
repeat 11 {
  let v = x * x - 5 * x;
  let cls = 0;
  if v < 0 {
    cls = 0 - 1;
  } else if v == 0 {
    cls = 0;
  } else if v < 20 {
    cls = 1;
  } else if v < 50 {
    cls = 2;
  } else {
    cls = 3;
  }
  print v;
  print cls;
  x = x + 1;
}

// group a modular shift value
let i = 0;
repeat 12 {
  let code = i * 7 % 26;
  let group = 0;
  if code < 9 {
    group = code + 1;
  } else if code < 18 {
    group = code * 2;
  } else {
    group = code - 5;
  }
  print code;
  print group;
  i = i + 1;
}

// nested range-then-parity classification
let n = 0;
repeat 12 {
  let tag = 0;
  if n < 6 {
    if n % 2 == 0 {
      tag = n * 10;
    } else {
      tag = n + 5;
    }
  } else {
    if n % 2 == 0 {
      tag = n * 100;
    } else {
      tag = n - 6;
    }
  }
  print tag;
  n = n + 1;
}

// classify a quotient with a guarded divisor
let n = 20;
repeat 8 {
  let d = n % 5 + 1;
  let q = 100 / d;
  let cls = 0;
  if q >= 50 {
    cls = 3;
  } else if q >= 20 {
    cls = 2;
  } else {
    cls = 1;
  }
  print q;
  print cls;
  n = n + 3;
}

// direction of change between successive computed values
let prev = 0;
let n = 3;
repeat 9 {
  let cur = n * n - 2 * n;
  let diff = cur - prev;
  let dir = 0;
  if diff > 0 {
    dir = 1;
  } else if diff < 0 {
    dir = 0 - 1;
  } else {
    dir = 0;
  }
  print cur;
  print dir;
  prev = cur;
  n = n + 1;
}

// classify the gap between two diverging accumulators
let a = 0;
let b = 100;
let i = 0;
repeat 10 {
  a = a + i * i;
  b = b - i;
  let tag = 0;
  if a > b {
    tag = a - b;
  } else if a == b {
    tag = 0;
  } else {
    tag = b - a;
  }
  print tag;
  i = i + 1;
}

// mod-3 duel outcome classification
let i = 0;
repeat 9 {
  let me = i % 3;
  let you = (i * 2 + 1) % 3;
  let res = 0;
  if me == you {
    res = 0;
  } else if (me + 1) % 3 == you {
    res = 0 - 1;
  } else {
    res = 1;
  }
  print me * 10 + you;
  print res;
  i = i + 1;
}

let sum = 0;
let i = 1;
repeat 10 {
  sum = sum + i;
  print sum;
  i = i + 1;
}

let fact = 1;
let n = 1;
repeat 6 {
  fact = fact * n;
  print fact;
  n = n + 1;
}

let p = 1;
repeat 8 {
  p = p * 2;
  print p;
}

let total = 0;
let k = 1;
repeat 7 {
  total = total + k * k;
  print total;
  k = k + 1;
}

let acc = 0;
let k = 1;
let sign = 1;
repeat 9 {
  acc = acc + sign * k;
  print acc;
  sign = -sign;
  k = k + 1;
}

let sum = 0;
let i = 1;
repeat 12 {
  sum = sum + i;
  if sum % 2 == 0 {
    print sum;
  } else {
    print -sum;
  }
  i = i + 1;
}

let a = 0;
let b = 1;
repeat 11 {
  let c = a + b;
  print c;
  a = b;
  b = c;
}

let prod = 1;
let k = 1;
repeat 6 {
  prod = prod * k;
  print prod;
  k = k + 2;
}

let sum = 0;
let i = 1;
repeat 15 {
  if i % 3 != 0 {
    sum = sum + i;
  }
  print sum;
  i = i + 1;
}

let p = 1;
let steps = 0;
repeat 7 {
  p = p * 3;
  if p > 100 && p % 2 == 1 {
    print p;
  } else {
    print steps;
  }
  steps = steps + 1;
}

let grand = 0;
let r = 1;
repeat 4 {
  let rowsum = 0;
  let c = 1;
  repeat 5 {
    rowsum = rowsum + r * c;
    c = c + 1;
  }
  grand = grand + rowsum;
  print rowsum;
  r = r + 1;
}
print grand;

let bal = 50;
repeat 8 {
  bal = bal + bal / 10 + 2;
  print bal;
}

let acc = 100;
repeat 6 {
  acc = acc - acc / 4;
  print acc;
}

let sum = 0;
let e = 2;
repeat 10 {
  sum = sum + e;
  print sum;
  e = e + 2;
}

let acc = 0;
let n = 1;
repeat 8 {
  acc = acc + 100 / n;
  print acc;
  n = n + 1;
}

let x = 27;
let steps = 0;
repeat 20 {
  if x == 1 {
    print steps;
  } else if x % 2 == 0 {
    x = x / 2;
    steps = steps + 1;
    print x;
  } else {
    x = x * 3 + 1;
    steps = steps + 1;
    print x;
  }
}

let p = 0;
let k = 1;
repeat 7 {
  p = k * (3 * k - 1) / 2;
  print p;
  k = k + 1;
}

let sum = 0;
let count = 0;
let v = 5;
repeat 6 {
  sum = sum + v;
  count = count + 1;
  print sum / count;
  v = v + 7;
}

let g = 1;
let i = 0;
repeat 9 {
  g = g * 2;
  if g > 64 || i == 0 {
    print g;
  } else {
    print i;
  }
  i = i + 1;
}

let grand = 0;
let n = 1;
repeat 6 {
  let dsum = 0;
  let d = 1;
  repeat n {
    if n % d == 0 {
      dsum = dsum + d;
    }
    d = d + 1;
  }
  grand = grand + dsum;
  print dsum;
  n = n + 1;
}
print grand;

let acc = 0;
let step = 10;
repeat 7 {
  acc = acc + step;
  step = step - 3;
  print acc;
}

let n = 2;
repeat 6 {
  let p = n * (n - 1);
  print p;
  n = n + 1;
}

let n = 0;
let evens = 0;
let odds = 0;
repeat 10 {
  if n % 2 == 0 { evens = evens + 1; } else { odds = odds + 1; }
  n = n + 1;
}
print evens;
print odds;
print evens == odds;
print evens > odds;

let x = 0;
let below = 0;
let atOrAbove = 0;
let threshold = 5;
repeat 12 {
  if x < threshold { below = below + 1; } else { atOrAbove = atOrAbove + 1; }
  x = x + 1;
}
print below;
print atOrAbove;
print below < atOrAbove;
print below >= threshold;

let a = 10;
let b = 0;
print b != 0 && a / b > 1;
print b == 0 || a / b > 1;
let safe = 0;
if b != 0 && a / b > 3 { safe = 1; } else { safe = 2; }
print safe;
print a > 5 && b < 5;

let n = 1;
let allEven = true;
let anyEven = false;
repeat 6 {
  allEven = allEven && n % 2 == 0;
  anyEven = anyEven || n % 2 == 0;
  n = n + 1;
}
print allEven;
print anyEven;
print n;

let n = 1;
let fizz = 0;
let buzz = 0;
repeat 15 {
  let byThree = n % 3 == 0;
  let byFive = n % 5 == 0;
  if byThree && byFive { fizz = fizz + 1; buzz = buzz + 1; }
  else if byThree { fizz = fizz + 1; }
  else if byFive { buzz = buzz + 1; }
  n = n + 1;
}
print fizz;
print buzz;
print fizz > buzz;
print fizz == 5 && buzz == 3;

let x = 3;
let inRange = x >= 1 && x <= 5;
let outLow = x < 1;
let outHigh = x > 5;
print inRange;
print outLow || outHigh;
print inRange != (outLow || outHigh);
print x;

let a = true;
let b = false;
let xor1 = (a || b) && !(a && b);
let c = true;
let d = true;
let xor2 = (c || d) && !(c && d);
let count = 0;
if xor1 { count = count + 1; }
if xor2 { count = count + 1; }
print xor1;
print xor2;
print count;
print xor1 == !xor2;

let cand = 7;
let d = 2;
let isPrime = true;
repeat 5 {
  if cand % d == 0 { isPrime = false; }
  d = d + 1;
}
print isPrime;
let cand2 = 9;
let d2 = 2;
let isPrime2 = true;
repeat 7 {
  if cand2 % d2 == 0 { isPrime2 = false; }
  d2 = d2 + 1;
}
print isPrime2;
print isPrime && !isPrime2;
print d;

let score = 72;
let grade = 0;
if score >= 90 { grade = 4; }
else if score >= 80 { grade = 3; }
else if score >= 70 { grade = 2; }
else if score >= 60 { grade = 1; }
else { grade = 0; }
print grade;
print score >= 70 && score < 80;
print grade >= 4 || score < 60;

let n = 0;
let hits = 0;
repeat 20 {
  let by2 = n % 2 == 0;
  let by3 = n % 3 == 0;
  if (by2 || by3) && !(by2 && by3) { hits = hits + 1; }
  n = n + 1;
}
print hits;
print hits > 0;
print hits < 20;
print hits % 2 == 0;

let pi = 0;
let mismatches = 0;
let checks = 0;
repeat 2 {
  let qi = 0;
  repeat 2 {
    let p = pi == 1;
    let q = qi == 1;
    let lhs = !(p && q);
    let rhs = !p || !q;
    if lhs != rhs { mismatches = mismatches + 1; }
    checks = checks + 1;
    qi = qi + 1;
  }
  pi = pi + 1;
}
print checks;
print mismatches;
print mismatches == 0;
print checks > mismatches;

let x = 0 - 4;
let isNeg = x < 0;
let isZero = x == 0;
let isPos = x > 0;
print isNeg;
print isZero || isPos;
let sign = 0;
if isNeg { sign = 0 - 1; } else if isPos { sign = 1; } else { sign = 0; }
print sign;
print isNeg && sign == 0 - 1;

let year = 2000;
let by4 = year % 4 == 0;
let by100 = year % 100 == 0;
let by400 = year % 400 == 0;
let leap = by4 && (!by100 || by400);
print leap;
let y2 = 1900;
let leap2 = y2 % 4 == 0 && (!(y2 % 100 == 0) || y2 % 400 == 0);
print leap2;
print leap && !leap2;
print year - y2;

let n = 16;
let ok = true;
let stop = false;
repeat 6 {
  if !stop {
    if n == 1 { stop = true; }
    else if n % 2 == 0 { n = n / 2; }
    else { ok = false; stop = true; }
  }
}
print ok;
print n;
print n == 1 && ok;
print n > 1;

let a = true;
let b = false;
